import{c as r,Q as a,j as e,m as d}from"./chunks/framework.BIBjCrbN.js";const p=JSON.parse('{"title":"神经工程 / 脑机接口方向","description":"中国顶尖高校神经工程与脑机接口方向博士导师汇总，包含侵入式/非侵入式BCI、神经信号处理、神经调控等子方向","frontmatter":{"title":"神经工程 / 脑机接口方向","description":"中国顶尖高校神经工程与脑机接口方向博士导师汇总，包含侵入式/非侵入式BCI、神经信号处理、神经调控等子方向"},"headers":[],"relativePath":"research-directions/bci.md","filePath":"research-directions/bci.md","lastUpdated":1780110618000}'),h={name:"research-directions/bci.md"};function n(i,t,o,l,s,u){return a(),e("div",null,[...t[0]||(t[0]=[d('<h1 id="神经工程-脑机接口-bci" tabindex="-1">神经工程 / 脑机接口 (BCI) <a class="header-anchor" href="#神经工程-脑机接口-bci" aria-label="Permalink to &quot;神经工程 / 脑机接口 (BCI)&quot;">​</a></h1><h2 id="方向概述" tabindex="-1">方向概述 <a class="header-anchor" href="#方向概述" aria-label="Permalink to &quot;方向概述&quot;">​</a></h2><p>神经工程与脑机接口是神经科学与工程技术的交叉领域，涉及神经信号的采集、解码、反馈与调控。国内此方向的研究力量主要集中在<strong>清华大学</strong>、<strong>浙江大学</strong>、<strong>中科院自动化所</strong>和<strong>天津大学</strong>。</p><h2 id="子方向" tabindex="-1">子方向 <a class="header-anchor" href="#子方向" aria-label="Permalink to &quot;子方向&quot;">​</a></h2><ul><li><strong>侵入式BCI</strong>：微电极阵列、ECoG、硬脑膜外电极 — 清华(洪波)、浙大(张韶岷)</li><li><strong>非侵入式BCI</strong>：EEG、fNIRS信号解码 — 清华(洪波)、天大</li><li><strong>脑机接口芯片/硬件</strong>：低功耗无线通信、芯片设计 — 浙大(赵博)</li><li><strong>神经信号处理与解码</strong>：机器学习、实时信号处理 — 多校</li><li><strong>神经调控</strong>：DBS、TMS、tACS — 浙大(张韶岷)</li><li><strong>闭环神经反馈系统</strong>：实时反馈、脑机融合 — 浙大(潘纲、郑能干)</li><li><strong>康复机器人/BCI应用</strong>：运动康复BCI — 中科院自动化所(侯增广)</li></ul><hr><h2 id="导师全索引" tabindex="-1">导师全索引 <a class="header-anchor" href="#导师全索引" aria-label="Permalink to &quot;导师全索引&quot;">​</a></h2><h3 id="清华大学" tabindex="-1">清华大学 <a class="header-anchor" href="#清华大学" aria-label="Permalink to &quot;清华大学&quot;">​</a></h3><table tabindex="0"><thead><tr><th>导师</th><th>职称</th><th>所在学院</th><th>核心方向</th><th>个人主页</th></tr></thead><tbody><tr><td><a href="/apply-phd/universities/tsinghua#洪波-长聘教授-博导">洪波</a></td><td>长聘教授</td><td>生物医学工程学院</td><td>无线微创BCI (NEO系统)、神经信号解码</td><td><a href="https://www.med.tsinghua.edu.cn/info/1142/2103.htm" target="_blank" rel="noreferrer">link</a></td></tr><tr><td>SONG SEN</td><td>教授</td><td>生物医学工程学院</td><td>神经工程与系统神经科学</td><td>—</td></tr><tr><td>苑克鑫</td><td>教授</td><td>生物医学工程学院</td><td>神经工程与系统神经科学</td><td>—</td></tr></tbody></table><h3 id="浙江大学" tabindex="-1">浙江大学 <a class="header-anchor" href="#浙江大学" aria-label="Permalink to &quot;浙江大学&quot;">​</a></h3><table tabindex="0"><thead><tr><th>导师</th><th>职称</th><th>所在学院</th><th>核心方向</th><th>个人主页</th></tr></thead><tbody><tr><td><a href="/apply-phd/universities/zju#潘纲-教授-求是特聘教授-博导">潘纲</a></td><td>教授、求是特聘</td><td>计算机学院</td><td>BCI算法/系统、类脑计算、脑机混合智能</td><td><a href="https://person.zju.edu.cn/gpan" target="_blank" rel="noreferrer">link</a></td></tr><tr><td><a href="/apply-phd/universities/zju#张韶岷-研究员-博导">张韶岷</a></td><td>研究员</td><td>生仪学院</td><td>植入式BCI、无创神经调控</td><td>—</td></tr><tr><td><a href="/apply-phd/universities/zju#郑能干-教授-博导">郑能干</a></td><td>教授</td><td>计算机学院</td><td>脑机混合智能、动物机器人</td><td><a href="https://person.zju.edu.cn/nengganzheng" target="_blank" rel="noreferrer">link</a></td></tr><tr><td><a href="/apply-phd/universities/zju#赵博-长聘教授-求是特聘教授-博导">赵博</a></td><td>长聘教授</td><td>集成电路学院</td><td>BCI芯片、生物医疗芯片</td><td><a href="https://person.zju.edu.cn/zhaobo" target="_blank" rel="noreferrer">link</a></td></tr><tr><td><a href="/apply-phd/universities/zju#庄柳静-百人计划研究员-博导">庄柳静</a></td><td>百人计划研究员</td><td>生仪学院</td><td>嗅觉BCI、仿生传感</td><td><a href="https://person.zju.edu.cn/0617206" target="_blank" rel="noreferrer">link</a></td></tr><tr><td><a href="/apply-phd/universities/zju#江海腾-研究员-博导">江海腾</a></td><td>研究员</td><td>—</td><td>神经工程、计算神经科学</td><td><a href="https://person.zju.edu.cn/HaitengJiang" target="_blank" rel="noreferrer">link</a></td></tr></tbody></table><h3 id="中国科学院" tabindex="-1">中国科学院 <a class="header-anchor" href="#中国科学院" aria-label="Permalink to &quot;中国科学院&quot;">​</a></h3><table tabindex="0"><thead><tr><th>导师</th><th>职称</th><th>所在单位</th><th>核心方向</th><th>个人主页</th></tr></thead><tbody><tr><td><a href="/apply-phd/universities/cas#侯增广-研究员-博导">侯增广</a></td><td>研究员、IEEE Fellow</td><td>自动化所</td><td>BCI与人机交互、康复机器人</td><td><a href="https://www.imaibj.cn/talent/details/000000110" target="_blank" rel="noreferrer">link</a></td></tr></tbody></table><h3 id="天津大学" tabindex="-1">天津大学 <a class="header-anchor" href="#天津大学" aria-label="Permalink to &quot;天津大学&quot;">​</a></h3><table tabindex="0"><thead><tr><th>导师</th><th>职称</th><th>所在学院</th><th>核心方向</th><th>个人主页</th></tr></thead><tbody><tr><td><a href="/apply-phd/universities/tju#明东-教授-博导-副校长">明东</a></td><td>教授、副校长</td><td>医学部/海河实验室</td><td>非侵入式BCI、&quot;神工&quot;系列、&quot;脑语者&quot;芯片、片上脑机接口</td><td>—</td></tr></tbody></table><blockquote><p>明东教授领导脑机交互与人机共融海河实验室，天津大学2025年新设全国首个&quot;脑机接口&quot;一级学科博士点。<strong>片上脑机接口方向（体外培养神经组织与机器连接）与你的类脑器官经验高度匹配！</strong></p></blockquote><h3 id="东南大学" tabindex="-1">东南大学 <a class="header-anchor" href="#东南大学" aria-label="Permalink to &quot;东南大学&quot;">​</a></h3><table tabindex="0"><thead><tr><th>导师</th><th>职称</th><th>所在学院</th><th>核心方向</th><th>个人主页</th></tr></thead><tbody><tr><td><a href="/apply-phd/universities/seu#顾忠泽-首席教授-博导">顾忠泽</a></td><td>首席教授、长江学者</td><td>BME学院/器官芯片研究院</td><td>类脑器官混合智能、电生理信号采集</td><td><a href="https://iirs.seu.edu.cn/2025/0604/c58381a530605/page.htm" target="_blank" rel="noreferrer">link</a></td></tr></tbody></table><blockquote><p>顾忠泽团队的&quot;基于人工类脑器官的混合智能&quot;方向，涉及类脑器官培养+电生理+机器人控制，与你的背景三位一体匹配。</p></blockquote><h3 id="复旦大学" tabindex="-1">复旦大学 <a class="header-anchor" href="#复旦大学" aria-label="Permalink to &quot;复旦大学&quot;">​</a></h3><table tabindex="0"><thead><tr><th>导师</th><th>职称</th><th>所在学院</th><th>核心方向</th></tr></thead><tbody><tr><td><a href="/apply-phd/universities/fudan#魏依娜-研究员-博导">魏依娜</a></td><td>研究员</td><td>脑智研究院</td><td>计算神经科学、脑机接口、睡眠与记忆</td></tr><tr><td><a href="/apply-phd/universities/fudan#刘裕峰-研究员-博导">刘裕峰</a></td><td>研究员</td><td>脑智研究院</td><td>AI+神经影像、类脑网络</td></tr></tbody></table><h3 id="北京大学" tabindex="-1">北京大学 <a class="header-anchor" href="#北京大学" aria-label="Permalink to &quot;北京大学&quot;">​</a></h3><table tabindex="0"><thead><tr><th>导师</th><th>职称</th><th>所在学院</th><th>核心方向</th></tr></thead><tbody><tr><td><a href="/apply-phd/universities/peking#吴思-教授-博导">吴思</a></td><td>教授</td><td>心理与认知科学学院</td><td>计算神经科学、神经信息编码</td></tr></tbody></table><hr><h2 id="对你推荐的导师" tabindex="-1">对你推荐的导师 <a class="header-anchor" href="#对你推荐的导师" aria-label="Permalink to &quot;对你推荐的导师&quot;">​</a></h2><p>基于你的背景（Imperial BME神经技术、UCL医用物理、脑类器官+EMG经历），推荐联系的优先级：</p><ol><li><strong>明东（天津大学）</strong> — 🏆 <strong>最推荐</strong>！片上脑机接口方向直接需要你的类脑器官培养+钙成像经验，且天大是全国唯一有BCI博士点的高校</li><li><strong>顾忠泽（东南大学）</strong> — 🏆 <strong>最推荐</strong>！类脑器官混合智能方向，器官芯片国家标准的制定者，平台资源顶级</li><li><strong>洪波（清华大学）</strong> — BCI领域最直接匹配，NEO系统的工程化思路与你的硬件+信号处理背景对口</li><li><strong>潘纲（浙江大学）</strong> — 脑机智能全国重点实验室主任，平台大、资源多</li><li><strong>侯增广（中科院）</strong> — 明确欢迎生物医学工程背景，BCI+康复机器人</li><li><strong>张韶岷（浙江大学）</strong> — 植入式BCI设备方向，你的神经技术+硬件背景是优势</li><li><strong>赵博（浙江大学）</strong> — BCI芯片硬件，你的电路设计经验有用</li><li><strong>魏依娜（复旦大学）</strong> — 计算神经科学+BCI，有海外背景</li></ol><h2 id="申请建议" tabindex="-1">申请建议 <a class="header-anchor" href="#申请建议" aria-label="Permalink to &quot;申请建议&quot;">​</a></h2><ul><li>BCI方向对<strong>信号处理</strong>和<strong>编程能力</strong>要求高，你的MATLAB/Python经验是核心竞争力</li><li><strong>硬件能力</strong>是加分项：很多纯生物/医学背景的申请人不会电路设计和嵌入式编程</li><li>建议在联系邮件中突出你的<strong>端到端原型开发能力</strong>（EMG项目从电路到算法全栈）</li><li>BCI方向是国内热门，提前联系导师尤为重要</li></ul>',29)])])}const g=r(h,[["render",n]]);export{p as __pageData,g as default};
